def get_session():
    driver.get("https://portal.app.flow.com.ar/login")
    time.sleep(2)
    for key, value in local_storage_data.items():
        driver.execute_script(f"localStorage.setItem('{key}', '{value}');")
    time.sleep(2)
    driver.refresh()

    time.sleep(2)
    token = driver.execute_script("return sessionStorage.getItem('fenix_chromecast');")
    sessionToken = json.loads(token)["sessionToken"]
    print("Session Token:", sessionToken)
    time.sleep(99999)
    return sessionToken
